import pandas as pd
from geopy.geocoders import Nominatim
from geopy.exc import GeocoderTimedOut

def get_location_info(address):
    geolocator = Nominatim(user_agent="geoapiExercises")
    try:
        location = geolocator.geocode(address)
        if location:
            return (location.latitude, location.longitude, location.address)
        else:
            return None
    except GeocoderTimedOut:
        return get_location_info(address)

def validate_location(address, latitude, longitude):
    location_info = get_location_info(address)
    if location_info is None:
        return False
    return (location_info[0] == latitude and location_info[1] == longitude)

def solve(file_path):
    df = pd.read_csv(file_path)
    results = []
    for index, row in df.iterrows():
        address = row['address']
        latitude = row['latitude']
        longitude = row['longitude']
        is_valid = validate_location(address, latitude, longitude)
        results.append({'address': address, 'is_valid': is_valid})
    return results
